// Legacy interface:
class OldLogger { writeLog(msg: string) {} }

// Modern interface:
interface Logger { log(level: string, msg: string): void; }

// Adapter:
class LoggerAdapter implements Logger {
  constructor(private old: OldLogger) {}
  log(level: string, msg: string) {
    this.old.writeLog(`[${level}] ${msg}`);
  }
}

interface ShippingStrategy {
  calculate(weight: number): number;
}

class DomesticShipping implements ShippingStrategy {
  calculate(weight: number) { return weight * 2; }
}

class Checkout {
  constructor(private strategy: ShippingStrategy) {}
  getShippingCost(weight: number) {
    return this.strategy.calculate(weight);
  }
}

interface Observer {
  update(event: Event): void;
}

class Subject {
  private observers: Observer[] = [];

  attach(o: Observer) { this.observers.push(o); }

  notify(event: Event) {
    this.observers.forEach(o => o.update(event));
  }
}
